import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"颐和园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace.md","filePath":"landmarks/summer-palace.md","lastUpdated":null}'),o={name:"landmarks/summer-palace.md"};function n(i,t,h,d,s,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="颐和园" tabindex="-1">颐和园 <a class="header-anchor" href="#颐和园" aria-label="Permalink to &quot;颐和园&quot;">​</a></h1><blockquote><p>&quot;十里青山行画里，双飞白鸟似江南。&quot; —— 明代诗人 王绂</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>颐和园是中国清朝时期皇家园林，坐落在北京西郊，距城区15公里，占地约290公顷，与圆明园毗邻。它是以昆明湖、万寿山为基址，以杭州西湖为蓝本，汲取江南园林的设计手法而建成的一座大型山水园林，也是保存最完整的一座皇家行宫御苑，被誉为&quot;皇家园林博物馆&quot;。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-20:00（旺季），6:30-19:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票30元，联票60元（含德和园、佛香阁、文昌院）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，夏季荷花最美</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线北宫门站或西苑站</td></tr><tr><td style="text-align:left;"><strong>预约方式</strong></td><td style="text-align:left;">颐和园官网或微信公众号预约</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>颐和园前身为清漪园，始建于乾隆十五年（1750年）。乾隆皇帝为庆祝其母崇庆皇太后六十大寿，在此修建清漪园，工程历时15年，耗银480万两。</p><h3 id="被毁与重建" tabindex="-1">被毁与重建 <a class="header-anchor" href="#被毁与重建" aria-label="Permalink to &quot;被毁与重建&quot;">​</a></h3><p>咸丰十年（1860年），英法联军入侵北京，清漪园被焚毁。光绪十二年（1886年），慈禧太后挪用海军军费重修此园，取&quot;颐养冲和&quot;之意，改名&quot;颐和园&quot;，作为晚年的颐养之所。</p><h3 id="劫难与修复" tabindex="-1">劫难与修复 <a class="header-anchor" href="#劫难与修复" aria-label="Permalink to &quot;劫难与修复&quot;">​</a></h3><p>光绪二十六年（1900年），八国联军入侵北京，颐和园再遭洗劫。解放后，政府多次对颐和园进行修缮，1961年被列为全国重点文物保护单位，1998年被列入《世界遗产名录》。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><p>颐和园由万寿山和昆明湖组成，大致可分为宫廷区、前山区、后山区、湖区四大部分。</p><h3 id="宫廷区" tabindex="-1">宫廷区 <a class="header-anchor" href="#宫廷区" aria-label="Permalink to &quot;宫廷区&quot;">​</a></h3><h4 id="仁寿殿" tabindex="-1">仁寿殿 <a class="header-anchor" href="#仁寿殿" aria-label="Permalink to &quot;仁寿殿&quot;">​</a></h4><p>仁寿殿是颐和园的政治活动区，慈禧太后和光绪皇帝曾在此处理朝政。殿前陈列着龙、凤、麒麟、太平有象等铜兽，象征着皇家的威仪。</p><h4 id="德和园" tabindex="-1">德和园 <a class="header-anchor" href="#德和园" aria-label="Permalink to &quot;德和园&quot;">​</a></h4><p>德和园是清代三大戏楼之一，与紫禁城畅音阁、承德避暑山庄清音阁齐名。戏楼共三层，可同时演出上天入地的神话戏剧。</p><h3 id="前山区" tabindex="-1">前山区 <a class="header-anchor" href="#前山区" aria-label="Permalink to &quot;前山区&quot;">​</a></h3><h4 id="佛香阁" tabindex="-1">佛香阁 <a class="header-anchor" href="#佛香阁" aria-label="Permalink to &quot;佛香阁&quot;">​</a></h4><p>佛香阁是颐和园的标志性建筑，高41米，八面三层四重檐，是颐和园全园的最高点。阁内供奉着一尊明代铜铸千手观音像。</p><h4 id="长廊" tabindex="-1">长廊 <a class="header-anchor" href="#长廊" aria-label="Permalink to &quot;长廊&quot;">​</a></h4><p>长廊全长728米，共273间，是中国古典园林中最长的游廊。廊内绘有14000余幅彩画，内容涵盖山水、花鸟、人物、故事等，被誉为&quot;世界第一长廊&quot;。</p><h4 id="排云殿" tabindex="-1">排云殿 <a class="header-anchor" href="#排云殿" aria-label="Permalink to &quot;排云殿&quot;">​</a></h4><p>排云殿是慈禧太后举行寿庆活动的地方，位于万寿山前山中央。殿名取&quot;神仙排云出，但见金银台&quot;之意。</p><h3 id="湖区" tabindex="-1">湖区 <a class="header-anchor" href="#湖区" aria-label="Permalink to &quot;湖区&quot;">​</a></h3><h4 id="昆明湖" tabindex="-1">昆明湖 <a class="header-anchor" href="#昆明湖" aria-label="Permalink to &quot;昆明湖&quot;">​</a></h4><p>昆明湖面积220公顷，占全园四分之三。湖中有南湖岛、藻鉴堂、治镜阁三座岛屿，象征蓬莱、方丈、瀛洲三座仙山。</p><h4 id="十七孔桥" tabindex="-1">十七孔桥 <a class="header-anchor" href="#十七孔桥" aria-label="Permalink to &quot;十七孔桥&quot;">​</a></h4><p>十七孔桥连接东堤和南湖岛，长150米，宽8米，是园内最大的石桥。桥上有形态各异的石狮544只，比卢沟桥还多。冬至前后，夕阳穿过桥洞，形成&quot;金光穿洞&quot;的奇观。</p><h4 id="西堤六桥" tabindex="-1">西堤六桥 <a class="header-anchor" href="#西堤六桥" aria-label="Permalink to &quot;西堤六桥&quot;">​</a></h4><p>仿杭州西湖苏堤而建，包括界湖桥、豳风桥、玉带桥、镜桥、练桥、柳桥六座桥，桥桥有景，景景不同。</p><h3 id="后山区" tabindex="-1">后山区 <a class="header-anchor" href="#后山区" aria-label="Permalink to &quot;后山区&quot;">​</a></h3><h4 id="苏州街" tabindex="-1">苏州街 <a class="header-anchor" href="#苏州街" aria-label="Permalink to &quot;苏州街&quot;">​</a></h4><p>苏州街又称&quot;买卖街&quot;，是仿照江南水街建造的皇家商业街。乾隆皇帝曾在此体验民间购物的乐趣。</p><h4 id="谐趣园" tabindex="-1">谐趣园 <a class="header-anchor" href="#谐趣园" aria-label="Permalink to &quot;谐趣园&quot;">​</a></h4><p>谐趣园仿无锡寄畅园而建，是颐和园中独立的江南园林，小巧精致，被称为&quot;园中之园&quot;。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="慈禧与海军军费" tabindex="-1">慈禧与海军军费 <a class="header-anchor" href="#慈禧与海军军费" aria-label="Permalink to &quot;慈禧与海军军费&quot;">​</a></h3><p>光绪年间，慈禧太后为修建颐和园，挪用海军军费约3000万两白银。这笔钱原本用于购买军舰、建设北洋水师。有说法认为，这笔钱若用于海军建设，甲午海战的结果或许会有所不同。</p><h3 id="石舫的故事" tabindex="-1">石舫的故事 <a class="header-anchor" href="#石舫的故事" aria-label="Permalink to &quot;石舫的故事&quot;">​</a></h3><p>清晏舫俗称&quot;石舫&quot;，位于昆明湖西北岸，是用巨石雕成的船形建筑。乾隆皇帝修建此舫，寓意&quot;水能载舟，亦能覆舟&quot;，告诫子孙要勤政爱民。</p><h3 id="知鱼桥的典故" tabindex="-1">知鱼桥的典故 <a class="header-anchor" href="#知鱼桥的典故" aria-label="Permalink to &quot;知鱼桥的典故&quot;">​</a></h3><p>谐趣园内的知鱼桥取自《庄子·秋水》中庄子与惠子&quot;濠梁之辩&quot;的故事，体现了中国古典哲学中&quot;知鱼之乐&quot;的智慧。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>北宫门入园路线（约4-5小时）</strong>：</p><p>北宫门 → 苏州街 → 须弥灵境 → 香岩宗印之阁 → 谐趣园 → 德和园 → 仁寿殿 → 玉澜堂 → 宜芸馆 → 乐寿堂 → 长廊 → 排云殿 → 佛香阁 → 石舫 → 乘船至南湖岛 → 十七孔桥 → 新建宫门</p><p><strong>东宫门入园路线（约4-5小时）</strong>：</p><p>东宫门 → 仁寿殿 → 德和园 → 玉澜堂 → 乐寿堂 → 长廊 → 排云殿 → 佛香阁 → 石舫 → 乘船 → 南湖岛 → 十七孔桥 → 铜牛 → 文昌院 → 东宫门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>联票推荐</strong>：佛香阁、德和园、文昌院是精华景点，建议购买联票</li><li><strong>游船体验</strong>：昆明湖游船（大船40元，小船60-80元/小时）是不错的体验</li><li><strong>荷花观赏</strong>：夏季（7-8月）昆明湖荷花盛开，非常壮观</li><li><strong>最佳拍摄点</strong>：佛香阁全景（南湖岛）、十七孔桥日落（东堤）</li><li><strong>避开人流</strong>：早上7:00-8:00或下午4:00后入园，避开旅行团</li></ol><h2 id="四季景色" tabindex="-1">四季景色 <a class="header-anchor" href="#四季景色" aria-label="Permalink to &quot;四季景色&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">特色景观</th><th style="text-align:left;">最佳观赏时间</th></tr></thead><tbody><tr><td style="text-align:left;">春</td><td style="text-align:left;">桃花、杏花</td><td style="text-align:left;">3月下旬-4月</td></tr><tr><td style="text-align:left;">夏</td><td style="text-align:left;">荷花满湖</td><td style="text-align:left;">7-8月</td></tr><tr><td style="text-align:left;">秋</td><td style="text-align:left;">银杏、红叶</td><td style="text-align:left;">10月下旬-11月</td></tr><tr><td style="text-align:left;">冬</td><td style="text-align:left;">雪景冰湖</td><td style="text-align:left;">12-2月</td></tr></tbody></table><hr><p><strong>📍 地址</strong>：北京市海淀区新建宫门路19号 <strong>📞 电话</strong>：010-62881144 <strong>🌐 官网</strong>：<a href="http://www.summerpalace-china.com" target="_blank" rel="noreferrer">www.summerpalace-china.com</a></p>',58)])])}const b=a(o,[["render",n]]);export{c as __pageData,b as default};
